mapper.select:
SELECT t.id, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, t.attendance_count AS attendanceCount, t.total_score AS totalScore FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id
AND (c.name LIKE CONCAT('%', #{query.keyword}, '%') OR th.name LIKE CONCAT('%', #{query.keyword}, '%'))
AND DATE(t.created_at) >= #{query.startDate}
AND DATE(t.created_at) <= #{query.endDate}
AND cs.teacher_id = #{currentTeacherId}
ORDER BY t.created_at DESC

SELECT t.id, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, t.attendance_count AS attendanceCount, t.total_score AS totalScore FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id WHERE t.id IN
#{id}
AND cs.teacher_id = #{currentTeacherId}
ORDER BY t.created_at DESC

SELECT t.id, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, t.attendance_count AS attendanceCount, t.total_score AS totalScore, sf.file_url AS fileUrl FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id LEFT JOIN sys_file sf ON t.file_id = sf.id
t.id = #{id}
AND cs.teacher_id = #{currentTeacherId}
